import{c as a,Q as i,j as p,m as t}from"./chunks/framework.hhGiamYR.js";const d=JSON.parse('{"title":"出使瓦伦蒂诺公爵","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/upper/35-出使瓦伦蒂诺公爵.md","filePath":"research/machiavelli/machiavelli/diplomatic/upper/35-出使瓦伦蒂诺公爵.md"}'),r={name:"research/machiavelli/machiavelli/diplomatic/upper/35-出使瓦伦蒂诺公爵.md"};function c(l,e,o,_,s,m){return i(),p("div",null,[...e[0]||(e[0]=[t('<h1 id="出使瓦伦蒂诺公爵" tabindex="-1">出使瓦伦蒂诺公爵 <a class="header-anchor" href="#出使瓦伦蒂诺公爵" aria-label="Permalink to &quot;出使瓦伦蒂诺公爵&quot;">​</a></h1><p>出使瓦伦蒂诺公爵</p><p>罗马涅，1502年10月-1503年1月</p><p>切萨雷 ·博尔贾是教皇亚历山大六世的次子，他父亲最初打算 让他在教会方面发展，并被提拔为瓦伦斯的枢机主教。但是，在其 长兄甘迪亚公爵遇刺一同时代所有的作家都将矛头指向切萨雷—之 后，他马上甩掉了枢机主教的帽子，迫不及待地拿起了剑，这对他 而言更为得心应手。教皇亚历山大六世赐予他一个还俗的敕令，派 遣他带着国书和给法国国王路易十二措辞恳切的推荐信前往法国， 同时他还带着一份教皇准许国王同让娜王后解除婚姻的敕令，这样 一来，国王就可以同查理八世的遗孀布列塔尼的安妮结婚，路易还 是奥尔良公爵的时候就深爱着安妮。与此同时，切萨雷 · 博尔贾还 给乔治 · 德 · 安布瓦兹一鲁昂大主教和路易十二的首相一带来了枢 机主教的头衔。为了对这些效忠表示认可，已经册封切萨雷为瓦伦 蒂诺公爵的国王，又将德 · 阿尔布雷大人的女儿夏洛特 ·德 · 阿尔 布雷许配给他；他还从乔治 · 得 · 安布瓦兹枢机主教那里得到了 援助和支持他在罗马涅建立一个他自己邦国的承诺，其父亚历山大 六世将此地赏赐给他，并动用教皇的军队进攻。然而，此时罗马涅 由为数众多的小领主和地方豪强所占据，他们中的一些人被瓦伦蒂 诺公爵雇佣，作为他部队的指挥官。那些唯恐公爵废黜他们的小领 主则秘密在佩鲁贾境内的马焦内开会，密谋策划对付公爵的手段。 然而公爵一从法国回来，就以异乎寻常的精力和手段展开了军事行 动，以迅雷不及掩耳之势就使自己成为了法恩扎、乌尔比诺等地的 主人。他也感到了取得佛罗伦萨共和国的支持并与其结盟的重要 性，因为其领土与罗马涅接壤，切萨雷请求佛罗伦萨执政团派出一 位大使前往他那里，以便他能洽谈此事。执政团于是派出了沃尔泰 拉枢机主教弗朗切斯科 · 索德里尼和尼科洛 · 马基雅维利前往乌尔 比诺与他会晤；但是公爵提出的缔结联盟的条件以及佛罗伦萨政府 进行改组的要求如此过分，显然他希望此举有利于他所设想的未来 对托斯卡纳的征服，因此使节团无法接受他的条件。公爵给了他们4 天时间考虑做出最后答复，在此期间，马基雅维利返回佛罗伦萨，</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>以咨询政府的意见；结果是执政团写信给索德里尼，要他通知公 爵，执政团不可能屈从于公爵的条件。 与此同时，由于在齐阿诺河谷和阿雷佐受到公爵派出的一些 部队指挥官一尤其是维泰洛佐 · 维泰利一的骚扰，佛罗伦萨政府变 得更加警惕。尽管这些骚扰都被平息，并且阿雷佐也在法国人的干 涉下回到了佛罗伦萨人手里，然而它们还是对佛罗伦萨政府产生了 很大影响，他们决定于1502年10月5日派出马基雅维利执行一次特 别任务，出使瓦伦蒂诺公爵，并留在他身边，观察他的一举一动。 正是这次任务产生了以下马基雅维利写给执政团的信件，其内容非 常有趣，尤其是它们包含对瓦伦蒂诺公爵在塞尼加利亚杀害维泰洛 佐 · 维泰利、奥利韦尔罗托 · 达 · 费尔莫、保罗大人和奥尔西尼家 族的格拉维纳公爵之过程的真实记述。</p><p>执政团决议①</p><p>1502年10月5日</p><p>杰出卓越的领主阁下： 尼科洛 · 马基雅维利接受我们的委派，出使如此伟大、非凡和谨慎的 君主瓦伦蒂诺公爵，他的薪金另外确定，关于他出使的具体情况如下所 示。他于10月6日出发，1502年1月23日返回。</p><p>①英译本未收入，依据贝尔泰利编校本译出。 ——中译者注</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>训 令</p>',12)])])}const h=a(r,[["render",c]]);export{d as __pageData,h as default};
